var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이상하군. 침식체들이 사라진 것도 모자라 CSE 레벨이 정상 수치로 돌아왔어.","JPN":"おかしい。侵食体が消えただけではなく、CSEレベルが正常値に戻った。","ENG":"Strange. Not only did the C.O.s vanish, but the CSE levels are back to normal.","TWN":"好奇怪。侵蝕體消失不見了，CSE等級也恢復到了正常數值。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관리국의 대처가 있었다고 해도… 너무 갑작스러운데.","JPN":"管理局の対処があったとしても……突然すぎる。","ENG":"Even if the Administration stepped in... this happened too fast.","TWN":"即使有管理局的應對……也太突然了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기사님! 크, 큰일입니다!","JPN":"騎士様！　た、大変です！","ENG":"Knight! There's a problem, a big one!","TWN":"騎士小姐！出、出大事了！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"원장님? 침식 경보가 해제되었다고는 해도 이렇게 돌아다니는 건 위험합니다.","JPN":"院長？　侵食警報が解除されたとはいえ、外を歩き回るのは危険です。","ENG":"Headmaster? The Corruption alert might be lifted, but it's still dangerous to be out here.","TWN":"院長？雖然侵蝕警報已經解除，但這樣到處走動還是很危險的。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그, 그게 중요한 게 아닙니다.","JPN":"そ、それどころではありません。","ENG":"Th-that's not the issue!","TWN":"那，那不是重點。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"엠마가… 엠마가 사라졌어요!","JPN":"エマが……エマがいないんです！","ENG":"Emma... Emma's gone!","TWN":"艾瑪……艾瑪消失了！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"읍! 으읍! 으으읍!!","JPN":"うっ！　うぶっ！　うぶぶっ！！","ENG":"Mmph! Mmmph! Mmmmmmph!!","TWN":"唔！嗚嗚！嗚嗚嗚！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"거 더럽게 시끄럽네. 얌전히 좀 있어라!","JPN":"うるさいな。大人しくしろ！","ENG":"Man, you're noisy. Sit still, would ya?","TWN":"真是吵死了。安靜點吧！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"형님. 괜찮을까요? 이 꼬맹이랑 같이 있던 여자. 저번에 그 망나니잖아요.","JPN":"兄貴。いいんですか？　このガキと一緒にいたあの女、この前のあいつじゃないですか。","ENG":"Sir, are we sure this is okay? That girl she was with, she's that psycho, right?","TWN":"大哥，沒問題嗎？和這個小鬼在一起的女人，就是上次那個混蛋啊。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"최근 블랙 네트워크에서 언급된 녀석이랑 동일 인물 같은데, 혹시 잘못 건드리면…….","JPN":"最近ブラックネットワークでうわさのやつと同一人物っぽいけど、下手したら……","ENG":"Pretty sure she's the one they've been talking about on the Dark Network. If we pissed her off...","TWN":"最近在黑色網路上提到的傢伙好像是同一個人，萬一惹錯了……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"그 로브 쓴 년이 망나니여봤자 우리 보스만 하겠냐?","JPN":"ローブの女が暴れたところで、うちのボスには敵わねえだろ。","ENG":"So what if she's nuts? You think she's tougher than our boss?","TWN":"那個穿袍子的傢伙再怎麼胡鬧，也比不上我們老闆吧？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"개죽음당하기 싫으면 그냥 얌전히 시키는 대로 해!","JPN":"死にたくなけりゃ黙って言う通りにしろ！","ENG":"Unless you want to die, shut up and do as you're told!","TWN":"不想白白送命的話，就乖乖聽話！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"읍! 으으읍!!","JPN":"うっ！　うぶぶ！！","ENG":"Mmmph! Mmmmmmph!!","TWN":"唔！嗚嗚唔！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"야, 인마. 그러게 전에 만났을 때 얌전히 굴었으면 좋았잖아.","JPN":"ったく、だからこの前大人しくすりゃよかったんだ。","ENG":"Hey, kid. You should've did what we asked when we first met.","TWN":"喂，夥計。早知道上次見面時乖乖聽話就好了吧。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"왜 귀찮게 굴어서 서로 피곤하게 만들어?","JPN":"抵抗するからお互い面倒なことになるんだぞ？","ENG":"Look at this mess. You're making this harder for both of us.","TWN":"為什麼要麻煩自己，讓彼此都累呢？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"혀, 형님…….","JPN":"あ、兄貴……","ENG":"S-sir...","TWN":"老……老大……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐! 너도 이제 나 무시하냐?","JPN":"んだよ！　お前まで俺のこと舐めてんのか！","ENG":"What?! You ignoring me too now?","TWN":"什麼！你也開始看我沒有嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"끄아아아악-!!","JPN":"くわああっ！！","ENG":"Gaaaah!","TWN":"呃啊啊啊-！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮나, 엠마?","JPN":"無事か、エマ？","ENG":"Emma, are you okay?","TWN":"沒事嗎，艾瑪？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"기, 기사니이임-!!","JPN":"き、騎士様あぁ！！","ENG":"Miss Knight!!","TWN":"騎，騎士姊姊-！！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐, 뭐야. 어떻게 이렇게 빨리 쫓아온 거야?","JPN":"な、なんだ。なんでこんなに早く追ってこられた？","ENG":"W-what the–?! How did she catch up so fast?!","TWN":"什、什麼啊。怎麼這麼快就追上來了？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오히려 이쪽에서 묻고 싶군. 대놓고 흔적을 남겨 함정인가 싶었는데.","JPN":"逆に聞きたいな。わかりやすい痕跡を残すものだから、罠かと思ったが。","ENG":"I should be asking you. You left such obvious tracks I thought it was a trap.","TWN":"我倒是想問問你。故意留下痕跡，是想設陷阱嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};